#include <stdio.h>
#include <string.h>

int main() {
    char questions[3][30] = {
        "Capital of France? ",
        "2 + 2 * 3 = ? ",
        "Color of the sky? "
    };
    char answers[3][20] = {"Paris", "8", "Blue"};
    char reply[40];
    int score = 0;
    for (int i = 0; i < 3; i++) {
        printf("%s", questions[i]);
        scanf("%s", reply);
        if (strcmp(reply, answers[i]) == 0) score++;
    }
    printf("You scored %d / 3\n", score);
    return 0;
}
